<?phpnamespace App\Http\Resources;use Illuminate\Http\Request;use Illuminate\Http\Resources\Json\JsonResource;class DeliveryRiderResource extends JsonResource{    /**     * Transform the resource into an array.     */    public function toArray(Request $request): array    {        return [            'id'        => $this->id,            'status'=>$this->status,            'phone_number'=>$this->phone_number,        ];    }}